#!/bin/bash
# OSC 777 para Kitty/WezTerm, OSC 9 para iTerm2/Windows Terminal
jq -n '{ terminalSequence: "\u001b]777;notify;Claude listo;Terminé de trabajar.\u0007\u001b]9;Claude listo\u0007" }'

#!/usr/bin/env python3
import sys, json, re

data = json.load(sys.stdin)
cmd  = data.get("tool_input", {}).get("command", "")

DANGEROUS = [
    r"rm\s+-rf\s+/",
    r">\s*/etc/",
    r"curl.*\|\s*bash",
    r"chmod\s+777"
]

for pattern in DANGEROUS:
    if re.search(pattern, cmd):
        print(json.dumps({
            "hookSpecificOutput": {
                "hookEventName": "PreToolUse",
                "permissionDecision": "deny",
                "permissionDecisionReason": f"Patrón peligroso detectado: {pattern}"
            }
        }))
        sys.exit(0)

sys.exit(0)  # sin decisión → flujo normal
